const express = require('express');
const bodyParser = require('body-parser');
const fs = require('fs');
const path = require('path');

const app = express();
app.use(bodyParser.json());

const plugins = [];

// Load plugins from configuration files or environment variables
function loadPlugins() {
    const pluginFiles = process.env.PLUGIN_FILES ? process.env.PLUGIN_FILES.split(',') : [];
    pluginFiles.forEach(file => {
        const filePath = path.resolve(__dirname, file.trim());
        if (fs.existsSync(filePath)) {
            const plugin = require(filePath);
            if (typeof plugin === 'function') {
                plugins.push(plugin);
            }
        }
    });
}

// Middleware to apply plugins
app.use((req, res, next) => {
    let modifiedReq = req;
    let modifiedRes = res;

    plugins.forEach(plugin => {
        const result = plugin(modifiedReq, modifiedRes);
        if (result) {
            modifiedReq = result.req || modifiedReq;
            modifiedRes = result.res || modifiedRes;
        }
    });

    next();
});

// Sample endpoint
app.get('/api/data', (req, res) => {
    res.json({ message: 'Hello from API Gateway!' });
});

// Load plugins on startup
loadPlugins();

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`API Gateway running on port ${PORT}`);
});